<header>
    <h1>Kanban Board</h1>
</header>

<div class="input-container">
    <input type="text" id="new-card" placeholder="Enter task title...">
    <button id="add-card">Add Card</button>
</div>

<div class="board">
    <!-- To Do Column -->
    <div id="col-todo" class="column" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">
        <div class="column-header">
            To Do <span class="count">0</span>
        </div>
        <div class="card-container"></div>
    </div>

    <!-- Doing Column -->
    <div id="col-doing" class="column" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">
        <div class="column-header">
            Doing <span class="count">0</span>
        </div>
        <div class="card-container"></div>
    </div>

    <!-- Done Column -->
    <div id="col-done" class="column" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">
        <div class="column-header">
            Done <span class="count">0</span>
        </div>
        <div class="card-container"></div>
    </div>
</div>

<script>
    // State Management
    let cards = [];

    const inputEl = document.getElementById('new-card');
    const addBtn = document.getElementById('add-card');
    const columns = ['#col-todo', '#col-doing', '#col-done'];

    // Initialize App
    function init() {
        const saved = localStorage.getItem('kanban-state');
        if (saved) {
            cards = JSON.parse(saved);
        }
        render();

        addBtn.addEventListener('click', addCard);
        inputEl.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') addCard();
        });
    }

    function save() {
        localStorage.setItem('kanban-state', JSON.stringify(cards));
    }

    function addCard() {
        const text = inputEl.value.trim();
        if (!text) return;

        const newCard = {
            id: 'card-' + Date.now(),
            text: text,
            columnId: 'col-todo'
        };

        cards.push(newCard);
        inputEl.value = '';
        save();
        render();
    }

    function deleteCard(id) {
        cards = cards.filter(c => c.id !== id);
        save();
        render();
    }

    // Drag and Drop Handlers
    function handleDragStart(e) {
        e.dataTransfer.setData('text/plain', e.target.dataset.id);
        e.target.classList.add('dragging');
    }

    function handleDragEnd(e) {
        e.target.classList.remove('dragging');
    }

    function handleDragOver(e) {
        e.preventDefault(); // Necessary to allow drop
        const column = e.currentTarget;
        column.classList.add('drag-over');
    }

    function handleDragLeave(e) {
        e.currentTarget.classList.remove('drag-over');
    }

    function handleDrop(e) {
        e.preventDefault();
        const column = e.currentTarget;
        column.classList.remove('drag-over');

        const cardId = e.dataTransfer.getData('text/plain');
        const targetColumnId = column.id;

        // Update state
        const cardIndex = cards.findIndex(c => c.id === cardId);
        if (cardIndex !== -1) {
            cards[cardIndex].columnId = targetColumnId;
            save();
            render();
        }
    }

    // UI Rendering
    function render() {
        // Clear all containers and counts
        columns.forEach(selector => {
            const col = document.querySelector(selector);
            const container = col.querySelector('.card-container');
            const countEl = col.querySelector('.count');
            container.innerHTML = '';
            countEl.textContent = '0';
        });

        // Populate columns
        cards.forEach(card => {
            const columnEl = document.getElementById(card.columnId);
            if (!columnEl) return;

            const container = columnEl.querySelector('.card-container');
            const countEl = columnEl.querySelector('.count');

            // Create Card Element
            const cardDiv = document.createElement('div');
            cardDiv.className = 'card';
            cardDiv.draggable = true;
            cardDiv.dataset.id = card.id;

            // Drag Events for the element itself
            cardDiv.addEventListener('dragstart', handleDragStart);
            cardDiv.addEventListener('dragend', handleDragEnd);

            const content = document.createElement('div');
            content.className = 'card-content';
            content.textContent = card.text;

            const delBtn = document.createElement('button');
            delBtn.className = 'card-del';
            delBtn.innerHTML = '&times;';
            delBtn.onclick = () => deleteCard(card.id);

            cardDiv.appendChild(content);
            cardDiv.appendChild(delBtn);
            container.appendChild(cardDiv);

            // Update count
            const currentCount = parseInt(countEl.textContent);
            countEl.textContent = currentCount + 1;
        });
    }

    init();
</script>

